#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <cmath>

struct Point {
    int x;
    int y;
};

extern double calculateDistance(const Point& p1, const Point& p2);

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        int x1, y1, x2, y2;
        ss >> x1 >> y1 >> x2 >> y2;
        Point p1 = {x1, y1};
        Point p2 = {x2, y2};
        std::cout << calculateDistance(p1, p2) << std::endl;
    }
    return 0;
}
